import { useState } from 'react';
import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';
import {
  ColumnDef,
  getCoreRowModel,
  useReactTable,
  flexRender,
  Row,
  HeaderGroup,
  Cell,
} from '@tanstack/react-table';
import { suppliers } from '@/lib/api';
import { Supplier } from '@/types';
import Layout from '@/components/Layout';

export default function SuppliersPage() {
  const queryClient = useQueryClient();
  const [data, setData] = useState<Supplier[]>([]);

  const { data: suppliersData, isLoading } = useQuery({
    queryKey: ['suppliers'],
    queryFn: suppliers.getAll,
  });

  const deleteMutation = useMutation({
    mutationFn: (id: number) => suppliers.delete(id),
    onSuccess: () => {
      queryClient.invalidateQueries({ queryKey: ['suppliers'] });
    },
  });

  const handleDelete = async (id: number) => {
    try {
      await deleteMutation.mutateAsync(id);
    } catch (error) {
      console.error('Error deleting supplier:', error);
    }
  };

  const columns: ColumnDef<Supplier>[] = [
    {
      accessorKey: 'name',
      header: 'Name',
    },
    {
      accessorKey: 'email',
      header: 'Email',
    },
    {
      accessorKey: 'phone',
      header: 'Phone',
    },
    {
      id: 'actions',
      cell: ({ row }: { row: Row<Supplier> }) => (
        <button
          onClick={() => handleDelete(row.original.id)}
          className="text-red-600 hover:text-red-800"
        >
          Delete
        </button>
      ),
    },
  ];

  const table = useReactTable({
    data: suppliersData || [],
    columns,
    getCoreRowModel: getCoreRowModel(),
  });

  if (isLoading) {
    return <div>Loading...</div>;
  }

  return (
    <Layout>
      <div className="container mx-auto px-4 py-8">
        <h1 className="text-2xl font-bold mb-6">Suppliers</h1>
        <div className="overflow-x-auto">
          <table className="min-w-full bg-white border border-gray-300">
            <thead>
              {table.getHeaderGroups().map((headerGroup: HeaderGroup<Supplier>) => (
                <tr key={headerGroup.id}>
                  {headerGroup.headers.map((header: HeaderGroup<Supplier>) => (
                    <th
                      key={header.id}
                      className="px-6 py-3 border-b border-gray-300 bg-gray-50 text-left text-xs leading-4 font-medium text-gray-500 uppercase tracking-wider"
                    >
                      {flexRender(
                        header.column.columnDef.header,
                        header.getContext()
                      )}
                    </th>
                  ))}
                </tr>
              ))}
            </thead>
            <tbody>
              {table.getRowModel().rows.map((row: Row<Supplier>) => (
                <tr key={row.id}>
                  {row.getVisibleCells().map((cell: Cell<Supplier, unknown>) => (
                    <td
                      key={cell.id}
                      className="px-6 py-4 whitespace-no-wrap border-b border-gray-300"
                    >
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </td>
                  ))}
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
    </Layout>
  );
}